body:
Currently Verilator doesn't support `tranif0` or `tranif1`. I tried to emulate it like this:

```
/* verilator lint_off UNOPTFLAT */
module connect_if_1(
    inout tri logic w0,
    inout tri logic w1,
    input var logic en
);
    assign w0 = en ? w1 : 'z;
    assign w1 = en ? w0 : 'z;
endmodule
/* verilator lint_on UNOPTFLAT */
```

Unfortunately a) it gives a warning that this is a combinatorial loop (which it technically is I guess), and b) it doesn't work. With the following testbench:

```

module tb;

  tri logic w0;
  tri logic w1;
  logic en;

  logic drv0_en;
  logic drv1_en;
  logic drv0_val;
  logic drv1_val;

  assign w0 = drv0_en ? drv0_val : 1'bz;
  assign w1 = drv1_en ? drv1_val : 1'bz;

  connect_if_1 dut (
    .w0(w0),
    .w1(w1),
    .en(en)
  );

  task show();
    $display("en=%b drv0=%s drv1=%s | w0=%b w1=%b",
      en,
      drv0_en ? (drv0_val ? "1" : "0") : "Z",
      drv1_en ? (drv1_val ? "1" : "0") : "Z",
      w0, w1
    );
  endtask

  initial begin
    en = 0;
    drv0_en = 0;
    drv1_en = 0;
    drv0_val = 0;
    drv1_val = 0;

    en = 1;

    drv0_en = 1; drv0_val = 1;
    drv1_en = 0;
    #1 show();

    drv0_en = 1; drv0_val = 0;
    drv1_en = 0;
    #1 show();

    $finish;
  end

endmodule
```

It prints

```
en=1 drv0=1 drv1=Z | w0=1 w1=1
en=1 drv0=0 drv1=Z | w0=1 w1=1
```

So when I drive `0` and `z` both wires are still 1 for some reason. I did try looking into the generated source. A bit too "generated" for me to follow but I think this is the relevant bit:

```
VL_INLINE_OPT void Vtb___024root___act_comb__TOP__0(Vtb___024root* vlSelf) {
    (void)vlSelf;  // Prevent unused variable warning
    Vtb__Syms* const __restrict vlSymsp VL_ATTR_UNUSED = vlSelf->vlSymsp;
    VL_DEBUG_IF(VL_DBG_MSGF("+    Vtb___024root___act_comb__TOP__0\n"); );
    auto& vlSelfRef = std::ref(*vlSelf).get();
    // Body
    vlSelfRef.tb__DOT__w1__strong__out4 = ((IData)(vlSelfRef.tb__DOT__en) 
                                           & (((IData)(vlSelfRef.tb__DOT__en) 
                                               & (IData)(vlSelfRef.tb__DOT__w0__strong__out2)) 
                                              | ((IData)(vlSelfRef.tb__DOT__drv0_en) 
                                                 & (IData)(vlSelfRef.tb__DOT__drv0_val))));
    vlSelfRef.tb__DOT__w1 = (((IData)(vlSelfRef.tb__DOT__en) 
                              & (IData)(vlSelfRef.tb__DOT__w1__strong__out4)) 
                             | ((IData)(vlSelfRef.tb__DOT__drv1_en) 
                                & (IData)(vlSelfRef.tb__DOT__drv1_val)));
    vlSelfRef.tb__DOT__w0__strong__out2 = ((IData)(vlSelfRef.tb__DOT__en) 
                                           & (((IData)(vlSelfRef.tb__DOT__en) 
                                               & (IData)(vlSelfRef.tb__DOT__w1__strong__out4)) 
                                              | ((IData)(vlSelfRef.tb__DOT__drv1_en) 
                                                 & (IData)(vlSelfRef.tb__DOT__drv1_val))));
    vlSelfRef.tb__DOT__w0 = (((IData)(vlSelfRef.tb__DOT__en) 
                              & (IData)(vlSelfRef.tb__DOT__w0__strong__out2)) 
                             | ((IData)(vlSelfRef.tb__DOT__drv0_en) 
                                & (IData)(vlSelfRef.tb__DOT__drv0_val)));
}
```

This doesn't work because first all of the values get set to 1 as expected, but then when we come back to this code with `drv0_val == 0` then nothing ever forces any of the wires back to 0 because `drv0_val` is only ever ORed into the existing values.

So my questions are:

1. Is this expected to work? (I'm guessing not?)
2. Can you think of any workarounds?

